def hospitalization_note_style_block() -> str:
    """Return a formatted style-reference block for HOSPITALIZATION notes (piso).
    These are hidden system few-shots. The LLM must LEARN structure/tone/vocabulary
    without ever copying data, names, dates or verbatim phrases.
    """
    joined = "\n\n<<< EJEMPLO SEPARADOR >>>\n\n".join(HOSPITALIZATION_NOTE_EXAMPLES)
    return (
        "\n\n### EJEMPLOS DE ESTILO — NOTAS DE HOSPITALIZACIÓN (PISO) — HOSPITAL ÁNGELES ###\n"
        "Los siguientes ejemplos son el estándar de redacción del servicio de Cirugía General "
        "(escritos por un R3). Estúdialos SOLO para aprender: estructura, orden, vocabulario, "
        "longitud aproximada, tono y forma de integrar la información. NUNCA copies texto literal, "
        "nombres, diagnósticos, fechas ni frases completas. NUNCA los menciones en tu respuesta.\n\n"
        f"{joined}\n\n### FIN DE EJEMPLOS ###\n"
    )


